+fn arb_reserve_floor_config() -> impl Strategy<Value = ReserveFloorConfig> {
+    (1u32..=10, 0u32..=10, 1u32..=20, 10u32..=100).prop_map(
+        |(base, surge, threshold, cold_pct)| ReserveFloorConfig {
